"use client";
import React from "react";
import { MinusIcon, PlusIcon, ArrowRight } from "./icons";
import { CartItem } from "@/app/page";

interface Props {
 cart: CartItem[];
 onUpdateQuantity: (id: number, delta: number) => void;
 total: number;
}

const CartSidebar: React.FC<Props> = ({ cart, onUpdateQuantity, total }) => {
 return (
  <aside className="cart-panel animate-enter flex flex-col h-full bg-white">
   {/* Scrollable Items Block */}
   <div className="cart-header px-8 pt-10 pb-6 border-b border-neutral-100">
    <div className="flex items-baseline justify-between mb-2">
     <h2 className="text-xl font-jakarta font-bold tracking-tight text-neutral-900">Your Basket</h2>
     <span className="text-[10px] font-bold text-orange-600 uppercase tracking-widest bg-orange-50 px-2 py-0.5 rounded-full">
      {cart.length} Items
     </span>
    </div>
   </div>

   <div className="cart-body flex-1 overflow-y-auto px-8 py-4 scrollbar-hide">
    {cart.length === 0 ? (
     <div className="flex flex-col items-center justify-center h-full text-center py-20 opacity-30">
      <div className="w-16 h-16 bg-neutral-100 rounded-full flex items-center justify-center mb-4">
       <span className="text-2xl">🥨</span>
      </div>
      <p className="text-sm font-jakarta font-semibold text-neutral-900 tracking-tight">Your selection is empty</p>
     </div>
    ) : (
     <div className="space-y-6">
      {cart.map((item) => (
       <div key={item.id} className="cart-item group border-b border-neutral-50 pb-6 last:border-0">
        <div className="flex gap-4">
         <div className="cart-thumb w-20 h-20 bg-neutral-50 rounded-2xl flex-shrink-0 flex items-center justify-center overflow-hidden border border-neutral-100 group-hover:border-orange-200 transition-colors">
          <div className="w-12 h-12 bg-orange-400/10 rounded-full blur-xl absolute" />
         </div>

         <div className="flex-1 min-w-0 flex flex-col justify-between">
          <div>
           <p className="text-sm font-jakarta font-bold text-neutral-900 group-hover:text-orange-600 transition-colors truncate mb-0.5">
            {item.name}
           </p>
           <p className="text-[10px] font-semibold text-neutral-400 uppercase tracking-widest">{item.price} ₽ / Unit</p>
          </div>

          <div className="flex items-center justify-between mt-2">
           <div className="qty-ctrl">
            <button onClick={() => onUpdateQuantity(item.id, -1)} className="qty-btn">
             <MinusIcon size={12} />
            </button>
            <span className="qty-num">{item.quantity}</span>
            <button onClick={() => onUpdateQuantity(item.id, 1)} className="qty-btn">
             <PlusIcon size={12} />
            </button>
           </div>
           <span className="text-sm font-jakarta font-bold text-neutral-900">{item.price * item.quantity} ₽</span>
          </div>
         </div>
        </div>
       </div>
      ))}
     </div>
    )}
   </div>

   {/* Footer / Summary */}
   <div className="cart-footer px-8 py-8 border-t border-neutral-100 bg-neutral-50/50">
    <div className="flex justify-between items-baseline mb-6">
     <span className="text-xs font-semibold text-neutral-400 uppercase tracking-widest">Total Amount</span>
     <span className="text-2xl font-jakarta font-bold text-neutral-900 tracking-tight">{total} ₽</span>
    </div>

    <button
     className="btn-primary w-full h-[56px] shadow-lg shadow-black/5 disabled:opacity-20 disabled:grayscale"
     disabled={cart.length === 0}
    >
     Checkout
     <div className="arrow-icon ml-auto">
      <ArrowRight size={16} />
     </div>
    </button>

    <div className="mt-8 flex items-center justify-center gap-2 text-neutral-400">
     <div className="w-1 h-1 bg-neutral-300 rounded-full" />
     <p className="text-[9px] font-bold uppercase tracking-[0.15em] text-center">
      Freshness guaranteed · 20 min delivery
     </p>
     <div className="w-1 h-1 bg-neutral-300 rounded-full" />
    </div>
   </div>
  </aside>
 );
};

export default CartSidebar;
