import React from "react";
import { PlusIcon } from "./icons";

interface Props {
 id: number;
 name: string;
 weight: string;
 price: number;
 oldPrice?: number;
 discount?: string;
 image: string;
 onAdd: () => void;
}

const ProductCard: React.FC<Props> = ({ name, weight, price, oldPrice, discount, image, onAdd }) => (
 <div className="product-card group reveal h-full flex flex-col">
  {/* Product Image */}
  <div className="img-wrap relative overflow-hidden bg-neutral-50 flex items-center justify-center p-8">
   {discount && (
    <span className="discount-badge">{discount}</span>
   )}

   <img
    src={image}
    alt={name}
    className="w-full h-full object-contain mix-blend-multiply transition-transform duration-700 ease-in-out group-hover:scale-110"
   />

   {/* Quick Add (Desktop) */}
   <div className="quick-add hidden md:block p-4">
    <button
     onClick={(e) => { e.stopPropagation(); onAdd(); }}
     className="btn-primary w-full shadow-lg"
    >
     Add to bag
     <div className="arrow-icon ml-auto">
      <PlusIcon size={16} />
     </div>
    </button>
   </div>
  </div>

  {/* Details */}
  <div className="card-body p-6 flex flex-col flex-1">
   <div className="flex flex-col gap-1 mb-4">
    <span className="text-orange-600 font-jakarta text-[10px] font-bold uppercase tracking-widest">
     Artisanal Breads
    </span>
    <h3 className="card-name text-neutral-900 font-jakarta font-semibold text-lg hover:text-orange-600 transition-colors">
     {name}
    </h3>
    <p className="card-weight text-neutral-400 font-inter text-xs font-medium uppercase tracking-wide">
     {weight}
    </p>
   </div>

   <div className="mt-auto flex items-center justify-between">
    <div className="flex items-baseline gap-2">
     <span className="card-price text-neutral-900 font-jakarta font-bold text-xl">{price} ₽</span>
     {oldPrice && (
      <span className="card-price-old text-neutral-400 font-inter text-sm line-through">{oldPrice} ₽</span>
     )}
    </div>

    {/* Mobile Circle Add */}
    <button
     onClick={(e) => { e.stopPropagation(); onAdd(); }}
     className="md:hidden w-10 h-10 rounded-full border border-neutral-200 flex items-center justify-center text-orange-600 active:bg-orange-500 active:text-white transition-all shadow-sm"
    >
     <PlusIcon size={18} />
    </button>
   </div>
  </div>
 </div>
);

export default ProductCard;
