"use client";
import React, { useState, useEffect } from "react";
import { SearchIcon, UserIcon, ClockIcon, ChefHatIcon } from "./icons";

const Header = ({ cartCount }: { cartCount: number }) => {
 const [scrolled, setScrolled] = useState(false);

 useEffect(() => {
  const fn = () => setScrolled(window.scrollY > 10);
  window.addEventListener("scroll", fn, { passive: true });
  return () => window.removeEventListener("scroll", fn);
 }, []);

 return (
  <nav className={`fixed top-0 left-0 right-0 z-[100] py-6 md:py-8 flex justify-between items-start transition-all duration-500 px-8 md:px-16 ${scrolled ? "bg-white/80 backdrop-blur-xl border-b border-neutral-100 py-4 shadow-sm" : ""
   }`}>
   {/* Brand */}
   <a href="#" className="flex items-center gap-3 group">
    <div className={`w-10 h-10 rounded-full flex items-center justify-center transition-all duration-300 shadow-lg ${scrolled
      ? "bg-orange-500 text-white shadow-orange-500/20"
      : "bg-white/10 backdrop-blur-xl border border-white/10 text-orange-400 group-hover:bg-white group-hover:text-orange-500 shadow-black/5"
     }`}>
     <ChefHatIcon size={20} />
    </div>
    <div className="flex flex-col justify-center">
     <span className={`font-jakarta font-bold text-lg leading-tight tracking-tight transition-colors duration-300 ${scrolled ? "text-neutral-900" : "text-white"
      }`}>
      Смысл Есть
     </span>
     <span className={`font-jakarta text-[10px] font-medium tracking-widest uppercase transition-colors duration-300 ${scrolled ? "text-neutral-500" : "text-white/70"
      }`}>
      Artisanal Bakery
     </span>
    </div>
   </a>

   {/* Actions & Status */}
   <div className="flex items-center gap-4 md:gap-6">
    <div className="hidden md:flex items-center gap-3">
     <span className={`px-4 py-2 rounded-full border text-xs font-medium tracking-wide flex items-center gap-2 transition-all duration-300 ${scrolled
       ? "border-neutral-200 bg-neutral-50 text-neutral-600"
       : "border-white/10 text-neutral-200 bg-black/20 backdrop-blur-md"
      }`}>
      <ClockIcon size={16} />
      До 22:00
     </span>
    </div>

    {/* Profile/Cart */}
    <button className="flex items-center gap-2.5 group relative">
     <div className={`w-10 h-10 rounded-full flex items-center justify-center transition-all duration-300 ${scrolled
       ? "bg-neutral-100 text-neutral-600 hover:bg-neutral-900 hover:text-white"
       : "bg-white/10 backdrop-blur-md border border-white/10 text-white hover:bg-white hover:text-neutral-900"
      }`}>
      <UserIcon size={18} />
     </div>
     {cartCount > 0 && (
      <span className="absolute -top-1 -right-1 min-w-[20px] h-[20px] bg-orange-500 text-white rounded-full flex items-center justify-center text-[10px] font-bold animate-enter">
       {cartCount}
      </span>
     )}
    </button>
   </div>
  </nav>
 );
};

export default Header;
